mapper.select:
SELECT n.id, n.room_id, n.recipient_id, n.actor_id, u.nickname AS actor_nickname, u.profile_image_url AS actor_profile_image_url, n.type, n.sub_type, n.reference_id, n.payload, n.is_read, n.created_at
FROM notifications n
LEFT JOIN users u ON u.id = n.actor_id
WHERE n.room_id = #{roomId}
  AND n.recipient_id = #{recipientId}

  AND n.type = #{type}


ORDER BY n.created_at DESC, n.id DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE notifications
SET is_read = true
WHERE id = #{id}

UPDATE notifications
SET is_read = true
WHERE room_id = #{roomId}
  AND recipient_id = #{recipientId}
  AND is_read = false
